module RefModule(
    input  clk,
    input  reset,
    input  d,
    output q
);

reg unused_q_reg;

always @(posedge clk or posedge reset) begin
    if (reset) begin
        unused_q_reg <= 1'b0;
    end else begin
        unused_q_reg <= d;
    end
end

assign q = unused_q_reg;

endmodule
